import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.B08aFN1B.js";const g=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md","lastUpdated":null}'),i={name:"getting-started.md"};function o(l,e,r,h,d,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="Getting-Started" tabindex="-1">Getting Started <a class="header-anchor" href="#Getting-Started" aria-label="Permalink to &quot;Getting Started {#Getting-Started}&quot;">​</a></h1><p>This walkthrough opens a notebook, builds a few reactive cells, adds a control, and hands a task to the AI agent.</p><h2 id="Open-a-notebook" tabindex="-1">Open a notebook <a class="header-anchor" href="#Open-a-notebook" aria-label="Permalink to &quot;Open a notebook {#Open-a-notebook}&quot;">​</a></h2><p>Run the <strong><code>slate</code> app</strong> (during the pre-release, install it with <code>pkg&gt; app dev https://github.com/kahliburke/KaimonSlate.jl</code> and then instantiate <code>~/.julia/dev/KaimonSlate</code> — see <a href="./installation">Installation</a> for the full steps):</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # start the hub + status TUI, and open the front page</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> intro.jl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # …or jump straight into a notebook (created if new)</span></span></code></pre></div><p><code>slate</code> starts (or attaches to) the notebook hub and shows a status TUI in your terminal. Under <strong>Kaimon</strong> it attaches to Kaimon&#39;s hub, so the <strong>💬 agent</strong> is available; standalone (<code>slate --own</code>) it owns the hub itself.</p><h3 id="The-front-page" tabindex="-1">The front page <a class="header-anchor" href="#The-front-page" aria-label="Permalink to &quot;The front page {#The-front-page}&quot;">​</a></h3><p>Plain <code>slate</code> opens the hub&#39;s <strong>front page</strong> in your browser (at <strong><code>http://127.0.0.1:8765</code></strong>) — the launcher for every notebook, and where you open or upload a document:</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/home.png" alt=""></p><ul><li><p><strong>Open by path</strong> — type a <code>.jl</code> path (Tab completes) and hit <strong>Open</strong>, or pass it on the shell as <code>slate path/to/notebook.jl</code>. A path that doesn&#39;t exist yet is created.</p></li><li><p><strong>⬆ Upload</strong> — pick a <code>.jl</code> from <em>this</em> computer; the hub saves it and opens it. (You can also just ask the <strong>💬 agent</strong> to open one.)</p></li><li><p><strong>Open notebooks</strong> — everything currently open on the hub; click to jump back in.</p></li><li><p><strong>Run on</strong> — choose where a notebook&#39;s worker runs: locally, or on a remote SSH host you set up with <strong>🖧 Remotes</strong>. See <a href="./remotes">Remotes</a>.</p></li><li><p><strong>☁ Publishing</strong> — manage published sites and destinations. See <a href="./publishing">Publishing</a>.</p></li></ul><p>Open one and you&#39;re in the notebook itself:</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/hero.png" alt=""></p><h2 id="Add-and-run-a-cell" tabindex="-1">Add and run a cell <a class="header-anchor" href="#Add-and-run-a-cell" aria-label="Permalink to &quot;Add and run a cell {#Add-and-run-a-cell}&quot;">​</a></h2><p>Click <strong>＋ cell</strong> (or press <code>b</code> in command mode to add below the selection). Type some Julia and run it:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span></span></code></pre></div><ul><li><p><strong>⇧⏎</strong> runs the cell.</p></li><li><p><strong>⌘⇧⏎</strong> (or <strong>Ctrl⇧⏎</strong>) runs and opens a fresh cell below — the keyboard &quot;next cell&quot; flow.</p></li></ul><p>A cell&#39;s left border shows its state: blue = fresh, gold = stale, orange = edited (unsaved), green = running, red = errored.</p><h2 id="reactivity" tabindex="-1">Reactivity <a class="header-anchor" href="#reactivity" aria-label="Permalink to &quot;Reactivity&quot;">​</a></h2><p>Add another cell that reads <code>x</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span></code></pre></div><p>Now change the first cell to <code>x = 50</code> and run it. The second cell <strong>restales and recomputes automatically</strong> — it depends on <code>x</code>, so KaimonSlate re-runs it for you. This is the core idea; see <a href="./reactivity">Reactive Cells</a>.</p><p>To see what feeds a cell, click the <strong>🔗</strong> button on its header: every upstream precursor lights up gold, and the view scrolls to the topmost one. Press <code>Esc</code> to clear.</p><h2 id="Add-a-control-with-@bind" tabindex="-1">Add a control with @bind <a class="header-anchor" href="#Add-a-control-with-@bind" aria-label="Permalink to &quot;Add a control with @bind {#Add-a-control-with-@bind}&quot;">​</a></h2><p>Controls are real Julia widget constructors. Add a bind cell:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> n </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Slider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Then read <code>n</code> from another cell:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CairoMakie</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set_theme!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">theme_dark</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">lines</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.^</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Drag the slider — the figure re-renders live. You can surface the control into another cell&#39;s <em>control strip</em> by dragging it, or open the <strong>🎛 Controls palette</strong> to see every declared <code>@bind</code>. See <a href="./widgets">Widgets &amp; @bind</a>.</p><div class="tip custom-block"><p class="custom-block-title">Insert a control fast</p><p>Press <strong>⌘K</strong> and type &quot;bind&quot; to insert any widget snippet (Slider, Toggle, Select, …) at the cursor.</p></div><h2 id="Markdown-and-math" tabindex="-1">Markdown and math <a class="header-anchor" href="#Markdown-and-math" aria-label="Permalink to &quot;Markdown and math {#Markdown-and-math}&quot;">​</a></h2><p>Switch a cell to markdown (<code>m</code> in command mode, or the <code>M↓</code> header button). Markdown cells render GitHub-flavored markdown, LaTeX math (<code>$…$</code> / <code>$$…$$</code>), and <strong>interpolation</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The answer is {{ x }}, and here is a chart: {{ echart(spec) }}</span></span></code></pre></div><h2 id="Hand-a-task-to-the-agent" tabindex="-1">Hand a task to the agent <a class="header-anchor" href="#Hand-a-task-to-the-agent" aria-label="Permalink to &quot;Hand a task to the agent {#Hand-a-task-to-the-agent}&quot;">​</a></h2><p>Open the <strong>💬 agent</strong> pane. Ask it to build something — it works incrementally, adding and running cells one at a time so you can watch:</p><blockquote><p>Plot the first 50 Fibonacci numbers on a log scale with ECharts.</p></blockquote><p>Click <strong>✨</strong> on a cell to scope a turn to that cell and its dependency cone, or type <strong>@</strong> in the chat to reference a specific cell by id. Pick the model and permission preset in <strong>⚙ Settings</strong>. See <a href="./agent">The AI Agent</a>.</p><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>When you&#39;re done, export from the <strong>☰</strong> menu: a self-contained <strong>HTML</strong> document, a publication-quality <strong>PDF</strong> (typeset server-side with Typst — themes, columns, vector figures), <strong>Print HTML</strong> for a quick browser PDF, or a fully reproducible <strong>self-contained <code>.jl</code></strong> (cells + environment + source). See <a href="./export">Export</a>.</p><h2 id="publish" tabindex="-1">Publish <a class="header-anchor" href="#publish" aria-label="Permalink to &quot;Publish&quot;">​</a></h2><p>To share it on the web, <strong>☰ → ☁ Publish…</strong> renders the notebook into a personal <strong>site</strong> — each document at its own URL behind a generated front page. One build deploys to GitHub Pages, Cloudflare, Netlify, or your own server, and you can mint a citable <strong>Zenodo DOI</strong> at milestones. Manage every site and target from the hub&#39;s <strong>☁ Publishing</strong> manager. See <a href="./publishing">Publishing</a>.</p>`,40)])])}const k=t(i,[["render",o]]);export{g as __pageData,k as default};
